const rows = $input.all().map(i => i.json);
const alerts = [];

function clean(value) {
  return String(value ?? '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function num(value) {
  const n = Number(String(value ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function parseDate(value) {
  const raw = clean(value);
  if (!raw) return null;
  const d = new Date(raw);
  if (!Number.isNaN(d.getTime())) {
    return d;
  }
  const m = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (m) {
    return new Date(`${m[1]}-${m[2]}-${m[3]}T00:00:00Z`);
  }
  return null;
}

function daysUntil(value) {
  const d = parseDate(value);
  if (!d) return null;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const target = new Date(d);
  target.setHours(0, 0, 0, 0);
  return Math.ceil((target - today) / 86400000);
}

function isActive(value) {
  const v = clean(value).toUpperCase();
  return ['TRUE', '1', 'JA', 'YES', 'AKTIV', 'ACTIVE'].includes(v);
}

function productName(row) {
  return clean(
    row.internal_product_name ||
    row.nayax_product_name ||
    row.product_name ||
    row.product_key ||
    'Unbekanntes Produkt'
  );
}

const now = new Date().toISOString();

// PATCH DEDUP_ALERTS: lade existierende Hinweise und baue Set
// fuer Type+ProductKey-Combos, die innerhalb der letzten DEDUP_DAYS Tage
// schon gemeldet wurden (resolved=FALSE). Diese werden im WF5-Run
// uebersprungen, sodass User nicht jeden Tag dieselbe Mail bekommt.
const DEDUP_DAYS = 7;
let existingHinweise = [];
try {
  existingHinweise = $('Google Sheets - Hinweise lesen').all().map(i => i.json);
} catch (e) {
  existingHinweise = [];
}
const dedupCutoff = new Date(Date.now() - DEDUP_DAYS * 24 * 60 * 60 * 1000);
const recentNotifications = new Set();
for (const h of existingHinweise) {
  const resolved = clean(h.resolved).toUpperCase();
  if (['TRUE','JA','YES','1','ERLEDIGT','RESOLVED'].includes(resolved)) continue;
  const createdRaw = clean(h.created_at);
  const created = parseDate(createdRaw);
  if (!created || created < dedupCutoff) continue;
  const key = clean(h.type) + '|' + clean(h.product_key) + '|' + clean(h.batch_id || '');
  recentNotifications.add(key);
}
function shouldEmitAlert(type, productKey, batchId) {
  const key = (type || '') + '|' + (productKey || '') + '|' + (batchId || '');
  if (recentNotifications.has(key)) return false;
  recentNotifications.add(key);  // Auch innerhalb diesem Lauf nicht doppelt melden
  return true;
}

// PATCH-A2c: Empty/Low-Batch Aggregat
// Ziel: Erkenne wenn Lagercharge-Summe pro product_key <= Schwellwert,
// unabhaengig vom (oft stale) current_machine_qty.
// low_batch_qty_threshold kommt aus Config-Node (default 5).
const config = ($('Config - WF5') ? $('Config - WF5').first()?.json : {}) || {};
const lowBatchThreshold = Number(config.low_batch_qty_threshold ?? 5);

const remainPerKey = new Map();
const sampleRowPerKey = new Map();
for (const row of rows) {
  const pk = clean(row.product_key);
  if (!pk) continue;
  const r = num(row.remaining_qty);
  // Nur aktive Chargen mit numerischem remaining zaehlen.
  // (Produkte-Zeilen ohne batch_id haben r=null und werden uebersprungen.)
  if (r === null) continue;
  const status = clean(row.status).toLowerCase();
  // Pro Lagercharge-Zeile: nur aktiv oder leer (nicht 'verbraucht'/'verworfen') beruecksichtigen.
  if (status && !['aktiv', 'leer'].includes(status)) continue;
  remainPerKey.set(pk, (remainPerKey.get(pk) || 0) + r);
  if (!sampleRowPerKey.has(pk)) sampleRowPerKey.set(pk, row);
}

const emittedBatchAlert = new Set();
for (const [pk, total] of remainPerKey.entries()) {
  if (total > lowBatchThreshold) continue;
  if (emittedBatchAlert.has(pk)) continue;
  const _typ = total <= 0 ? 'EMPTY_BATCH' : 'LOW_BATCH';
  if (!shouldEmitAlert(_typ, pk, '')) { emittedBatchAlert.add(pk); continue; }
  const sample = sampleRowPerKey.get(pk) || {};
  const name = productName(sample);
  const crit = total <= 0;
  alerts.push({
    created_at: now,
    type: crit ? 'EMPTY_BATCH' : 'LOW_BATCH',
    severity: crit ? 'critical' : 'warning',
    product_key: pk,
    product_name: name,
    internal_product_name: clean(sample.internal_product_name),
    nayax_product_name: clean(sample.nayax_product_name),
    machine_id: clean(sample.machine_id),
    mdb_code: clean(sample.mdb_code),
    total_remaining_qty: total,
    threshold: lowBatchThreshold,
    message: crit
      ? `${name}: Lagerbestand ist 0 - Produkt komplett leer.`
      : `${name}: Nur noch ${total} Stueck im Lager (Schwellwert ${lowBatchThreshold}).`
  });
  emittedBatchAlert.add(pk);
}

for (const row of rows) {
  const productKey = clean(row.product_key);
  if (!productKey) continue;

  // Nur aktive Zeilen berÃ¼cksichtigen
  const active =
    isActive(row.active) ||
    isActive(row.status) ||
    isActive(row.replenishment_status);
  if (!active) continue;

  const name = productName(row);
  const currentMachineQty = num(row.current_machine_qty);
  const minStock = num(row.min_stock);
  const targetStock = num(row.target_stock);
  const machineCapacity = num(row.machine_capacity);
  const mhd = clean(row.mhd);
  const remainingQty = num(row.remaining_qty);
  const days = daysUntil(mhd);

  // MHD Warnung
  if (mhd && days !== null && days <= 30 && shouldEmitAlert('MHD_WARNING', productKey, clean(row.batch_id))) {
    alerts.push({
      created_at: now,
      type: 'MHD_WARNING',
      severity: days < 0 ? 'critical' : 'warning',
      product_key: productKey,
      product_name: name,
      internal_product_name: clean(row.internal_product_name),
      nayax_product_name: clean(row.nayax_product_name),
      batch_id: clean(row.batch_id),
      mhd,
      remaining_qty: remainingQty,
      machine_id: clean(row.machine_id),
      mdb_code: clean(row.mdb_code),
      message:
        days < 0
          ? `${name}: Charge ${clean(row.batch_id)} ist seit ${Math.abs(days)} Tag(en) abgelaufen.`
          : `${name}: Charge ${clean(row.batch_id)} lÃ¤uft in ${days} Tag(en) ab.`
    });
  }

  // PATCH AUTO_REFILL_WF5: LOW_STOCK informativ statt warning/critical,
  // DEDUP: nur einmal pro 7 Tage
  // weil WF3 auto-refill den Slot beim naechsten Sale heilt.
  if (
    currentMachineQty !== null &&
    minStock !== null &&
    machineCapacity !== null &&
    machineCapacity > 0 &&
    currentMachineQty < minStock &&
    shouldEmitAlert('LOW_STOCK', productKey, '')
  ) {
    alerts.push({
      created_at: now,
      type: 'LOW_STOCK',
      severity: 'info',
      product_key: productKey,
      product_name: name,
      internal_product_name: clean(row.internal_product_name),
      nayax_product_name: clean(row.nayax_product_name),
      machine_id: clean(row.machine_id),
      mdb_code: clean(row.mdb_code),
      current_machine_qty: currentMachineQty,
      min_stock: minStock,
      target_stock: targetStock,
      machine_capacity: machineCapacity,
      message: currentMachineQty <= 0
        ? `${name}: Slot laut Sheet leer - wird beim naechsten Sale auto-aufgefuellt.`
        : `${name}: Slot laut Sheet bei ${currentMachineQty} Stueck.`
    });
  }
}

// PATCH AUTO_RESOLVE_WF5: Offene Hinweise auflÃ¶sen wenn Bedingung nicht mehr gilt
// Wird tÃ¤glich von WF5 geprÃ¼ft - User muss resolved=TRUE nie mehr manuell setzen.
const autoResolveHints = [];
for (const h of existingHinweise) {
  const hResolved = String(h.resolved ?? '').trim().toUpperCase();
  if (['TRUE','JA','YES','1','ERLEDIGT','RESOLVED'].includes(hResolved)) continue;
  const hType = String(h.type ?? '').trim();
  const hPk   = String(h.product_key ?? '').trim();
  const hCat  = clean(h.created_at);
  if (!hType || !hPk || !hCat) continue;

  let shouldAutoResolve = false;

  if (['EMPTY_BATCH', 'INSUFFICIENT_BATCH_STOCK'].includes(hType)) {
    const totalRemain = remainPerKey.get(hPk) || 0;
    if (totalRemain > 0) shouldAutoResolve = true;
  }
  if (hType === 'LOW_BATCH') {
    const totalRemain = remainPerKey.get(hPk) || 0;
    if (totalRemain > lowBatchThreshold) shouldAutoResolve = true;
  }
  if (hType === 'LOW_STOCK') {
    // Resolve wenn irgendein aktiver Produkte-Slot fÃ¼r diesen product_key >= min_stock
    const productRow = rows.find(r =>
      String(r.product_key ?? '').trim() === hPk &&
      isActive(r.active) &&
      r.current_machine_qty !== undefined &&
      r.min_stock !== undefined
    );
    if (productRow) {
      const cmq  = num(productRow.current_machine_qty);
      const minS = num(productRow.min_stock);
      if (cmq !== null && minS !== null && cmq >= minS) shouldAutoResolve = true;
    }
  }

  if (shouldAutoResolve) {
    autoResolveHints.push({ created_at: hCat, resolved: 'TRUE' });
  }
}

return [{
  json: {
    alerts,
    autoResolveHints,
    summary: {
      checked_batches: rows.length,
      alerts_created: alerts.length,
      auto_resolved: autoResolveHints.length,
      created_at: now
    }
  }
}];

const source = $input.all()
  .map(i => i.json)
  .find(item => Array.isArray(item.alerts) && item.summary && item.summary.alerts_created !== undefined);

return ((source && source.alerts) || []).map(alert => ({ json: alert }));

// WF5 Mail-Builder â€” Single-Source aus PostgreSQL (Dashboard-Digest).
// Holt /api/v2/alerts/digest (PG-Fakten) und rendert die Report-Mail daraus.
// Bestand kommt aus PG (nicht mehr Google Sheets); AUTO_REFILL_SLOT/info-
// Hinweise zÃ¤hlen NICHT mehr als Workflow-Fehler.
const cfg = (() => { try { return $('Config - WF5').first().json || {}; } catch (e) { return {}; } })();
const DIGEST_URL = cfg.digest_url || 'http://homelab-dashboard:8787/api/v2/alerts/digest';

let digest = {};
try {
  const resp = await this.helpers.httpRequest({ method: 'GET', url: DIGEST_URL, json: true });
  digest = (resp && resp.data) ? resp.data : (resp || {});
} catch (e) {
  digest = { _error: String(e && e.message || e) };
}

const mhdExpired   = digest.mhdExpired   || [];
const mhdSoon      = digest.mhdSoon      || [];
const emptySlots   = digest.emptySlots   || [];
const lowBatches   = digest.lowBatches   || [];
const emptyBatches = digest.emptyBatches || [];
const dataIssues   = digest.dataIssues   || [];

function clean(v) { return String(v == null ? '' : v).replace(/\s+/g, ' ').trim(); }
function esc(v) {
  return clean(v).replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function formatDate(v) {
  const raw = clean(v);
  if (!raw) return '-';
  const d = new Date(raw);
  if (Number.isNaN(d.getTime())) return raw;
  return d.toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: 'numeric' });
}
const dateText = new Date().toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: 'numeric' });

function card(title, count, color) {
  return '<td style="width:50%;padding:8px;"><div style="border:1px solid #e5e7eb;border-radius:12px;background:#ffffff;padding:14px;">' +
    '<div style="font-size:12px;color:#6b7280;margin-bottom:4px;">' + esc(title) + '</div>' +
    '<div style="font-size:26px;font-weight:700;color:' + color + ';">' + count + '</div></div></td>';
}
function section(title, itemsHtml) {
  if (!itemsHtml) return '';
  return '<h2 style="font-size:18px;margin:28px 0 10px;color:#111827;">' + esc(title) + '</h2>' +
    '<div style="border:1px solid #e5e7eb;border-radius:12px;overflow:hidden;background:#ffffff;">' + itemsHtml + '</div>';
}
function itemBlock(lines) {
  return '<div style="padding:14px 16px;border-bottom:1px solid #e5e7eb;">' +
    lines.filter(Boolean).map(function (l) {
      return '<div style="margin:4px 0;font-size:14px;line-height:1.35;">' + l + '</div>';
    }).join('') + '</div>';
}

function mhdBlock(a) {
  const days = a.days_remaining;
  const daysText = (days == null) ? 'Datum prÃ¼fen'
    : (days < 0 ? 'seit ' + Math.abs(days) + ' Tag(en) abgelaufen' : 'in ' + days + ' Tag(en)');
  return itemBlock([
    esc(a.product_name) + (a.machine_id ? ' | Maschine: ' + esc(a.machine_id) : '') + (a.batch_key ? ' | Charge: ' + esc(a.batch_key) : ''),
    'MHD: ' + esc(formatDate(a.mhd_date)) + ' | ' + esc(daysText) + ' | Restmenge: ' + (a.remaining_qty != null ? esc(a.remaining_qty) : '-')
  ]);
}
function slotBlock(a) {
  return itemBlock([
    esc(a.product_name) + (a.machine_id ? ' | Maschine: ' + esc(a.machine_id) : '') + (a.mdb_code ? ' | MDB: ' + esc(a.mdb_code) : ''),
    'Bestand im Automaten: ' + esc(a.current_machine_qty != null ? a.current_machine_qty : 0)
  ]);
}
function batchBlock(a) {
  return itemBlock([
    esc(a.product_name) + (a.product_key ? ' | SKU: ' + esc(a.product_key) : ''),
    'Lagerbestand: ' + esc(a.total_remaining_qty != null ? a.total_remaining_qty : 0) + ' (Schwellwert ' + esc(a.threshold != null ? a.threshold : 5) + ')'
  ]);
}
function issueBlock(a) {
  return itemBlock([
    esc(a.entity || a.warning_type || 'Hinweis') + ' | Typ: ' + esc(a.warning_type || '-') + ' | Schweregrad: ' + esc(a.severity || '-'),
    a.message ? 'Hinweis: ' + esc(a.message) : ''
  ]);
}

const batchAlerts = emptyBatches.concat(lowBatches);

const subjectParts = [];
if (mhdExpired.length)  subjectParts.push(mhdExpired.length + ' MHD abgelaufen');
if (mhdSoon.length)     subjectParts.push(mhdSoon.length + ' MHD bald');
if (emptySlots.length)  subjectParts.push(emptySlots.length + ' leere Slots');
if (batchAlerts.length) subjectParts.push(batchAlerts.length + ' Lager niedrig');
if (dataIssues.length)  subjectParts.push(dataIssues.length + ' Datenfehler');
const subject = subjectParts.length
  ? 'Automatenlager Check ' + dateText + ': ' + subjectParts.join(' | ')
  : 'Automatenlager Check ' + dateText + ': keine akuten Punkte';

const nextSteps = [];
if (mhdExpired.length)  nextSteps.push('Abgelaufene Produkte sofort aus Automat/Lager entfernen.');
if (mhdSoon.length)     nextSteps.push('Produkte mit nahendem MHD priorisiert verkaufen oder austauschen.');
if (emptySlots.length)  nextSteps.push('Leere Automaten-Slots fÃ¼r die nÃ¤chste BefÃ¼llung einplanen.');
if (batchAlerts.length) nextSteps.push('Niedrige LagerbestÃ¤nde nachbestellen.');
if (dataIssues.length)  nextSteps.push('Daten-/Workflowfehler prÃ¼fen (Monitoring/Dashboard).');
if (!nextSteps.length)  nextSteps.push('Keine Aktion erforderlich.');

const errBanner = digest._error
  ? '<div style="background:#fef2f2;border:1px solid #fecaca;color:#7f1d1d;border-radius:12px;padding:12px 14px;margin-bottom:18px;font-size:13px;">Digest-Endpunkt nicht erreichbar: ' + esc(digest._error) + '</div>'
  : '';

const html =
  '<div style="font-family:Arial,Helvetica,sans-serif;background:#f3f4f6;padding:24px;color:#111827;">' +
  '<div style="max-width:780px;margin:0 auto;background:#ffffff;border-radius:16px;padding:24px;border:1px solid #e5e7eb;">' +
  '<h1 style="font-size:24px;margin:0 0 4px;">Automatenlager Check</h1>' +
  '<div style="font-size:14px;color:#6b7280;margin-bottom:6px;">Datum: ' + esc(dateText) + '</div>' +
  '<div style="font-size:12px;color:#9ca3af;margin-bottom:18px;">Datenquelle: PostgreSQL (live)</div>' +
  errBanner +
  '<table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border-collapse:separate;border-spacing:0;margin-bottom:18px;">' +
  '<tr>' + card('MHD abgelaufen', mhdExpired.length, '#b91c1c') + card('MHD lÃ¤uft bald ab', mhdSoon.length, '#b45309') + '</tr>' +
  '<tr>' + card('Leere Slots (Automat)', emptySlots.length, '#1d4ed8') + card('Lager niedrig/leer', batchAlerts.length, '#b45309') + '</tr>' +
  '<tr>' + card('Daten-/Workflowfehler', dataIssues.length, '#7f1d1d') + card('', '', '#ffffff') + '</tr>' +
  '</table>' +
  section('MHD abgelaufen', mhdExpired.map(mhdBlock).join('')) +
  section('MHD lÃ¤uft bald ab', mhdSoon.map(mhdBlock).join('')) +
  section('Leere Automaten-Slots', emptySlots.map(slotBlock).join('')) +
  section('Lagerbestand niedrig/leer', batchAlerts.map(batchBlock).join('')) +
  section('Daten-/Workflowfehler', dataIssues.map(issueBlock).join('')) +
  '<h2 style="font-size:18px;margin:28px 0 10px;">NÃ¤chste Schritte</h2>' +
  '<ul style="margin:0;padding-left:20px;">' +
  nextSteps.map(function (s) { return '<li style="margin:6px 0;font-size:14px;line-height:1.35;">' + esc(s) + '</li>'; }).join('') +
  '</ul>' +
  '<div style="font-size:12px;color:#6b7280;margin-top:28px;border-top:1px solid #e5e7eb;padding-top:12px;">Automatisch erstellt durch n8n Â· Quelle: Dashboard /api/v2/alerts/digest (PostgreSQL).</div>' +
  '</div></div>';

const text = [
  'Automatenlager Check ' + dateText + ' (Quelle: PostgreSQL)',
  '',
  'MHD abgelaufen: ' + mhdExpired.length,
  'MHD lÃ¤uft bald ab: ' + mhdSoon.length,
  'Leere Slots (Automat): ' + emptySlots.length,
  'Lager niedrig/leer: ' + batchAlerts.length,
  'Daten-/Workflowfehler: ' + dataIssues.length
].join('\n');

return [{
  json: {
    email_subject: subject,
    email_body: html,
    email_text: text,
    source: 'postgres-digest',
    mhd_expired_count: mhdExpired.length,
    mhd_soon_count: mhdSoon.length,
    empty_slots_count: emptySlots.length,
    batch_alert_count: batchAlerts.length,
    data_issue_count: dataIssues.length,
    digest_error: digest._error || null
  }
}];

const rows = $input.all().map(i => i.json);

function clean(v) {
  return String(v ?? '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function isResolved(v) {
  const s = clean(v).toUpperCase();
  return ['TRUE', 'JA', 'YES', '1', 'ERLEDIGT', 'RESOLVED'].includes(s);
}

function parseDate(v) {
  const raw = clean(v);
  if (!raw) return null;
  const d = new Date(raw);
  if (!Number.isNaN(d.getTime())) return d;
  return null;
}

function todayBerlinIso() {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(new Date());
  return [
    parts.find(p => p.type === 'year')?.value,
    parts.find(p => p.type === 'month')?.value,
    parts.find(p => p.type === 'day')?.value,
  ].join('-');
}

function isFromToday(row) {
  const raw = clean(row.created_at);
  if (!raw) return true;
  const d = parseDate(raw);
  if (!d) return true;
  const day = d.toLocaleDateString('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  return day === todayBerlinIso();
}

// Typen die frisch berechnet werden - nicht aus Fehler_und_Hinweise lesen
const SKIP_TYPES = new Set(['LOW_STOCK', 'MHD_WARNING', 'MHD_EXPIRED']);

const seen = new Set();

const alerts = rows
  .filter(row => !isResolved(row.resolved))
  .filter(row => isFromToday(row))
  .filter(row => !SKIP_TYPES.has(clean(row.type).toUpperCase()))
  .filter(row => {
    const key = `${clean(row.type)}|${clean(row.product_key)}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .map(row => ({
    created_at: clean(row.created_at),
    type: clean(row.type || 'OPEN_HINT'),
    severity: clean(row.severity || 'warning'),
    machine_id: clean(row.machine_id),
    product_key: clean(row.product_key),
    nayax_product_name: clean(row.nayax_product_name),
    internal_product_name: clean(row.internal_product_name),
    product_name: clean(row.product_name || row.nayax_product_name || row.internal_product_name || row.product_key),
    mdb_code: clean(row.mdb_code || row.actual_mdb_code || row.expected_mdb_code),
    message: clean(row.message),
    resolved: clean(row.resolved),
    change_id: clean(row.change_id),
    source: 'Fehler_und_Hinweise'
  }));

return [{
  json: {
    alerts,
    summary: {
      checked_hint_rows: rows.length,
      open_hints_today: alerts.length,
      created_at: new Date().toISOString()
    }
  }
}];

const rows = $input.all().map(i => i.json);

function clean(value) {
  return String(value ?? '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function num(value) {
  const n = Number(String(value ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
}

function todayBerlinIso() {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(new Date());

  return [
    parts.find(p => p.type === 'year')?.value,
    parts.find(p => p.type === 'month')?.value,
    parts.find(p => p.type === 'day')?.value,
  ].join('-');
}

function parseDate(value) {
  const raw = clean(value);
  if (!raw) return null;
  const d = new Date(raw);
  return Number.isNaN(d.getTime()) ? null : d;
}

function berlinDay(value) {
  const d = parseDate(value);
  if (!d) return '';
  return d.toLocaleDateString('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
}

function berlinTime(value) {
  const d = parseDate(value);
  if (!d) return '';
  return d.toLocaleTimeString('de-DE', {
    timeZone: 'Europe/Berlin',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function saleDate(row) {
  return clean(row.settlement_datetime_gmt || row.SettlementDateTimeGMT || row.processed_at);
}

const today = todayBerlinIso();
const salesByProduct = new Map();
let transactionsToday = 0;
let quantityToday = 0;

for (const row of rows) {
  const status = clean(row.status).toUpperCase();
  if (status.startsWith('SKIPPED')) continue;

  const dateValue = saleDate(row);
  if (berlinDay(dateValue) !== today) continue;

  const productKey = clean(row.product_key) || 'UNBEKANNT';
  const name = clean(row.nayax_product_name || row.product_name || productKey);
  const qty = num(row.quantity || 1) || 1;
  const key = `${productKey}|${name}`;

  if (!salesByProduct.has(key)) {
    salesByProduct.set(key, {
      product_key: productKey,
      product_name: name,
      nayax_product_name: name,
      quantity_sold_today: 0,
      transactions_today: 0,
      first_sale_time: '',
      last_sale_time: '',
      statuses: new Set(),
      machine_ids: new Set(),
    });
  }

  const entry = salesByProduct.get(key);
  entry.quantity_sold_today += qty;
  entry.transactions_today += 1;
  if (!entry.first_sale_time) entry.first_sale_time = berlinTime(dateValue);
  entry.last_sale_time = berlinTime(dateValue) || entry.last_sale_time;
  if (status) entry.statuses.add(status);
  if (clean(row.machine_id)) entry.machine_ids.add(clean(row.machine_id));

  transactionsToday += 1;
  quantityToday += qty;
}

const daily_sales = [...salesByProduct.values()]
  .map(entry => ({
    ...entry,
    statuses: [...entry.statuses].join(', '),
    machine_ids: [...entry.machine_ids].join(', '),
  }))
  .sort((a, b) => b.quantity_sold_today - a.quantity_sold_today || a.product_name.localeCompare(b.product_name, 'de'));

return [{
  json: {
    daily_sales,
    daily_sales_totals: {
      day: today,
      products_sold_today: daily_sales.length,
      transactions_today: transactionsToday,
      quantity_sold_today: quantityToday,
      checked_transaction_rows: rows.length,
    },
    summary: {
      checked_transaction_rows: rows.length,
      sales_today_products: daily_sales.length,
      sales_today_transactions: transactionsToday,
      sales_today_quantity: quantityToday,
      created_at: new Date().toISOString()
    }
  }
}];

// PATCH AUTO_RESOLVE_WF5: Gibt autoResolveHints als einzelne Items zurÃ¼ck.
// Wenn keine EintrÃ¤ge vorhanden  kein Item  Google-Sheets-Update wird nicht ausgefÃ¼hrt.
const hints = ($input.first()?.json?.autoResolveHints) || [];
