return hints.map(h => ({ json: h }));

const batchRunId = "wf5_" + new Date().toISOString().slice(0, 10);

function clean(value) {
  return String(value ?? "").replace(/\n/g, " ").replace(/\s+/g, " ").trim();
}

function sanitize(value) {
  return clean(value).toUpperCase().replace(/[^A-Z0-9]+/g, "_").replace(/^_+|_+$/g, "");
}

function warningType(type) {
  const normalized = clean(type).toUpperCase();
  return normalized === "MHD_WARNING" ? "MHD_NEAR" : normalized || "WF5_WARNING";
}

function numericOrUndefined(value) {
