const rows = $input.all().map(i => i.json);

function clean(value) {
  return String(value ?? '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function num(value) {
  const n = Number(String(value ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
}

function todayBerlinIso() {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(new Date());

  return [
    parts.find(p => p.type === 'year')?.value,
    parts.find(p => p.type === 'month')?.value,
    parts.find(p => p.type === 'day')?.value,
  ].join('-');
}

function parseDate(value) {
  const raw = clean(value);
  if (!raw) return null;
  const d = new Date(raw);
  return Number.isNaN(d.getTime()) ? null : d;
}

function berlinDay(value) {
  const d = parseDate(value);
  if (!d) return '';
  return d.toLocaleDateString('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
}

function berlinTime(value) {
  const d = parseDate(value);
  if (!d) return '';
  return d.toLocaleTimeString('de-DE', {
    timeZone: 'Europe/Berlin',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function saleDate(row) {
  return clean(row.settlement_datetime_gmt || row.SettlementDateTimeGMT || row.processed_at);
}

const today = todayBerlinIso();
const salesByProduct = new Map();
let transactionsToday = 0;
let quantityToday = 0;

for (const row of rows) {
  const status = clean(row.status).toUpperCase();
  if (status.startsWith('SKIPPED')) continue;

  const dateValue = saleDate(row);
  if (berlinDay(dateValue) !== today) continue;

  const productKey = clean(row.product_key) || 'UNBEKANNT';
  const name = clean(row.nayax_product_name || row.product_name || productKey);
  const qty = num(row.quantity || 1) || 1;
  const key = `${productKey}|${name}`;

  if (!salesByProduct.has(key)) {
    salesByProduct.set(key, {
      product_key: productKey,
      product_name: name,
      nayax_product_name: name,
      quantity_sold_today: 0,
      transactions_today: 0,
      first_sale_time: '',
      last_sale_time: '',
      statuses: new Set(),
      machine_ids: new Set(),
    });
  }

  const entry = salesByProduct.get(key);
  entry.quantity_sold_today += qty;
  entry.transactions_today += 1;
  if (!entry.first_sale_time) entry.first_sale_time = berlinTime(dateValue);
  entry.last_sale_time = berlinTime(dateValue) || entry.last_sale_time;
  if (status) entry.statuses.add(status);
  if (clean(row.machine_id)) entry.machine_ids.add(clean(row.machine_id));

  transactionsToday += 1;
  quantityToday += qty;
}

const daily_sales = [...salesByProduct.values()]
  .map(entry => ({
    ...entry,
    statuses: [...entry.statuses].join(', '),
    machine_ids: [...entry.machine_ids].join(', '),
  }))
  .sort((a, b) => b.quantity_sold_today - a.quantity_sold_today || a.product_name.localeCompare(b.product_name, 'de'));

return [{
  json: {
    daily_sales,
    daily_sales_totals: {
      day: today,
      products_sold_today: daily_sales.length,
      transactions_today: transactionsToday,
      quantity_sold_today: quantityToday,
      checked_transaction_rows: rows.length,
    },
    summary: {
      checked_transaction_rows: rows.length,
      sales_today_products: daily_sales.length,
      sales_today_transactions: transactionsToday,
      sales_today_quantity: quantityToday,
      created_at: new Date().toISOString()
    }
  }
}];

